import React from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const Feature = ({ icon, titulo, desc }) => (
  <div style={{
    background: 'var(--color-background-primary)',
    border: '0.5px solid var(--color-border-tertiary)',
    borderRadius: 16, padding: '2rem',
    textAlign: 'center', transition: 'transform 0.2s, box-shadow 0.2s',
  }}
    onMouseEnter={e => { e.currentTarget.style.transform='translateY(-4px)'; e.currentTarget.style.boxShadow='0 12px 32px rgba(0,0,0,0.1)'; }}
    onMouseLeave={e => { e.currentTarget.style.transform='translateY(0)'; e.currentTarget.style.boxShadow='none'; }}
  >
    <div style={{ fontSize: 42, marginBottom: 16 }}>{icon}</div>
    <h3 style={{ fontSize: 16, fontWeight: 600, marginBottom: 8, color: 'var(--color-text-primary)' }}>{titulo}</h3>
    <p style={{ fontSize: 14, color: 'var(--color-text-secondary)', lineHeight: 1.6 }}>{desc}</p>
  </div>
);

const Stat = ({ num, label }) => (
  <div style={{ textAlign: 'center' }}>
    <div style={{ fontSize: 36, fontWeight: 700, color: '#5eead4', marginBottom: 4 }}>{num}</div>
    <div style={{ fontSize: 13, color: 'rgba(255,255,255,0.7)' }}>{label}</div>
  </div>
);

export default function HomePage() {
  const { usuario } = useAuth();

  return (
    <div>
      {/* HERO BANNER */}
      <div style={{
        background: 'linear-gradient(135deg, #0f172a 0%, #1e3a8a 50%, #0f766e 100%)',
        padding: '5rem 2rem',
        textAlign: 'center',
        position: 'relative',
        overflow: 'hidden',
      }}>
        {/* Círculos decorativos */}
        <div style={{ position:'absolute', top:-80, right:-80, width:300, height:300, borderRadius:'50%', background:'rgba(255,255,255,0.03)' }}/>
        <div style={{ position:'absolute', bottom:-60, left:-60, width:200, height:200, borderRadius:'50%', background:'rgba(255,255,255,0.03)' }}/>

        {/* Logo grande */}
        <div style={{ display:'flex', justifyContent:'center', marginBottom:24 }}>
          <img src="/Logo-RedNorte.png" alt="RedNorte" style={{ height:100, width:'auto', filter:'drop-shadow(0 4px 24px rgba(0,0,0,0.3))' }}/>
        </div>

        <h1 style={{ fontSize: 48, fontWeight: 800, color: 'white', marginBottom: 8, lineHeight: 1.1 }}>
          Red<span style={{ color: '#5eead4' }}>Norte</span>
        </h1>
        <p style={{ fontSize: 16, color: 'rgba(255,255,255,0.6)', marginBottom: 16, letterSpacing: '2px', textTransform:'uppercase' }}>
          Sistema de Gestión de Listas de Espera
        </p>
        <p style={{ fontSize: 18, color: 'rgba(255,255,255,0.85)', maxWidth: 560, margin: '0 auto 40px', lineHeight: 1.7 }}>
          Plataforma inteligente para la gestión de citas médicas en el sistema público de salud. Rápido, transparente y accesible.
        </p>

        <div style={{ display:'flex', gap:16, justifyContent:'center', flexWrap:'wrap' }}>
          {usuario ? (
            <Link to="/mis-consultas" style={{
              background: '#2563EB', color: 'white', padding: '14px 32px',
              borderRadius: 30, fontWeight: 600, fontSize: 16, textDecoration: 'none',
              boxShadow: '0 4px 20px rgba(37,99,235,0.4)',
            }}>Ver mis consultas →</Link>
          ) : (
            <>
              <Link to="/login" style={{
                background: 'white', color: '#1e3a8a', padding: '14px 32px',
                borderRadius: 30, fontWeight: 700, fontSize: 16, textDecoration: 'none',
                boxShadow: '0 4px 20px rgba(0,0,0,0.2)',
              }}>Iniciar sesión</Link>
              <Link to="/registro" style={{
                background: 'rgba(255,255,255,0.15)', color: 'white', padding: '14px 32px',
                borderRadius: 30, fontWeight: 600, fontSize: 16, textDecoration: 'none',
                border: '1px solid rgba(255,255,255,0.3)',
              }}>Registrarse</Link>
            </>
          )}
        </div>

        {/* Stats */}
        <div style={{ display:'grid', gridTemplateColumns:'repeat(3,1fr)', gap:32, maxWidth:500, margin:'56px auto 0' }}>
          <Stat num="24/7" label="Disponible siempre" />
          <Stat num="100%" label="Sistema público" />
          <Stat num="0$" label="Costo para pacientes" />
        </div>
      </div>

      {/* FEATURES */}
      <div style={{ padding:'5rem 2rem', maxWidth:1000, margin:'0 auto' }}>
        <h2 style={{ textAlign:'center', fontSize:28, fontWeight:700, marginBottom:8, color:'var(--color-text-primary)' }}>
          ¿Qué puedes hacer en RedNorte?
        </h2>
        <p style={{ textAlign:'center', color:'var(--color-text-secondary)', marginBottom:48, fontSize:15 }}>
          Todo lo que necesitas para gestionar tu atención médica en un solo lugar
        </p>

        <div style={{ display:'grid', gridTemplateColumns:'repeat(3,1fr)', gap:20, marginBottom:40 }}>
          <Feature icon="📋" titulo="Solicita una consulta" desc="Ingresa tus síntomas y especialidad médica. El sistema te asigna automáticamente a la lista de espera correcta." />
          <Feature icon="📍" titulo="Seguimiento en tiempo real" desc="Consulta el estado de tu cita en cualquier momento. Sabrás exactamente en qué punto está tu solicitud." />
          <Feature icon="🔄" titulo="Reasignación automática" desc="Si alguien cancela, el sistema reasigna la cita automáticamente al siguiente paciente en espera." />
          <Feature icon="🩺" titulo="Ficha médica digital" desc="Completa tu perfil médico con alergias, medicamentos y condiciones. El médico tendrá toda la info antes de verte." />
          <Feature icon="🔒" titulo="100% seguro" desc="Tus datos médicos están protegidos y solo el personal autorizado puede acceder a ellos." />
          <Feature icon="📱" titulo="Acceso desde cualquier lugar" desc="Usa RedNorte desde tu computador, tablet o teléfono. Sin instalaciones, solo tu navegador." />
        </div>

        {/* CTA final */}
        {!usuario && (
          <div style={{
            background: 'linear-gradient(135deg, #1e3a8a, #0f766e)',
            borderRadius: 20, padding: '3rem 2rem', textAlign:'center', color:'white',
          }}>
            <h3 style={{ fontSize:24, fontWeight:700, marginBottom:12 }}>¿Listo para empezar?</h3>
            <p style={{ color:'rgba(255,255,255,0.8)', marginBottom:24, fontSize:15 }}>
              Crea tu cuenta gratis y solicita tu primera consulta médica hoy mismo.
            </p>
            <Link to="/registro" style={{
              background:'white', color:'#1e3a8a', padding:'12px 32px',
              borderRadius:30, fontWeight:700, fontSize:15, textDecoration:'none',
            }}>Crear cuenta gratis</Link>
          </div>
        )}
      </div>
    </div>
  );
}
